+// String returns a human-readable description of the active trust options and configured IP ranges.
+func (c *ipChecker) String() string {
+	var opts []string
+	if c.trustLoopback {
+		opts = append(opts, "loopback")
+	}
+	if c.trustLinkLocal {
+		opts = append(opts, "link-local")
+	}
+	if c.trustPrivateNet {
+		opts = append(opts, "private-net")
+	}
+	for _, r := range c.trustExtraRanges {
+		opts = append(opts, r.String())
+	}
+	if len(opts) == 0 {
+		return "ipChecker{trust: none}"
+	}
+	return "ipChecker{trust: " + strings.Join(opts, ", ") + "}"
+}
